    public CloudPanoramaItem(String title, String url, String coverFileName, String category) {
        this.id = coverFileName;
        this.title = title;
        this.url = url;
        this.coverUrl = ASSET_COVER_DIR + coverFileName;
        this.category = category;
    }

    public boolean matches(String query) {
        if (query == null || query.trim().length() == 0) return true;
        return title.toLowerCase().contains(query.trim().toLowerCase());
    }

